sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);
	
	function TestCase_AppBuilderImplementBusinessProcess(vApp,business_process,vExpected)
	{
		function TestCase_AppBuilderImplementBusinessProcess_CheckResult(vInput,vExpected,vResult)
		{
			if (vResult == true)
			{
				var grApp = GetAppRecord(vInput.vApp);
				test.Log('All files contained in the app:');
				var grMetadata = new GlideRecord('sys_metadata');
				grMetadata.addQuery('sys_scope','=',grApp.sys_id);
				grMetadata.query();
				while (grMetadata.next())
				{
					test.Log(RenderRecordSummary(grMetadata));
				}
			}
			return (vExpected == vResult);
		}
		
		test.TestCase(
			'Function AppBuilderImplementBusinessProcess()',
			AppBuilderImplementBusinessProcess,
			{
				'vApp': vApp,
				'business_process': business_process
			},
			vExpected,
			TestCase_AppBuilderImplementBusinessProcess_CheckResult);
	}
		
	TestCase_AppBuilderImplementBusinessProcess(null,null,false);

	var grApp = new GlideRecord('sys_app');
	grApp.initialize();
	grApp.name = '_ATF_TEST_PROCESS';
	grApp.scope = 'x_test_process';
	GlideRecordInsert(grApp);

	TestCase_AppBuilderImplementBusinessProcess(grApp,null,false);

	var business_process = BusinessProcessGetExample();
	delete business_process.id;
	TestCase_AppBuilderImplementBusinessProcess(grApp,business_process,false);

	var business_process = BusinessProcessGetExample();
	TestCase_AppBuilderImplementBusinessProcess(grApp,business_process,true);

	
	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
